/**
 * Writes root supabase-config.js from process.env (Vercel build or local .env).
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import dotenv from "dotenv";

const root = path.join(path.dirname(fileURLToPath(import.meta.url)), "..");
dotenv.config({ path: path.join(root, ".env") });

const url = (process.env.SUPABASE_URL || "").trim();
const key = (process.env.SUPABASE_ANON_KEY || "").trim();
const apiUrl = (process.env.SINGLEWORD_API_URL || "").trim();

const body =
  "/* Auto-generated by npm run build — do not commit real secrets */\n" +
  `window.__SUPABASE_URL=${JSON.stringify(url)};\n` +
  `window.__SUPABASE_ANON_KEY=${JSON.stringify(key)};\n` +
  `window.__SINGLEWORD_API_URL=${JSON.stringify(apiUrl)};\n`;

fs.writeFileSync(path.join(root, "supabase-config.js"), body, "utf8");
console.log("[write-supabase-config] wrote supabase-config.js", {
  hasUrl: Boolean(url),
  hasKey: Boolean(key),
  hasApiUrl: Boolean(apiUrl),
});
